function generateToken() {
  // 1. create a variable to hold a token string, and set it equal to an empty string
  let token = "";

  // 2. create a variable that holds the alphabet we'll be using in our tokens (lowercase letters)
  
  const alphabet = "abcdefghijklmnopqrstuvwxyz";
  console.log(alphabet);

// 3.  create a for loop that will run as many times as there are elements in the alphabet variable. Inside the loop,
  // create another variable to hold an index value. Use the length property of the alphabet variable inside your for loop.

  for (let i = 0; i < alphabet.length; i++) {
    console.log(alphabet[i]);
//    4.  generate a random number using Math.random() and multiply that by the length of our alphabet variable, then convert it to an integer. We'll use this index as a way of randomly selecting letters from the alphabt.
    const rand = Math.floor(Math.random()*alphabet.length)
// 5.  create another variable to hold a token letter. Set that equal to the string at position i in our alphabet array, using bracket notation.
    let tokenLetter = alphabet[rand];
//6. Concatenate this new random letter onto your token string.
    console.log(tokenLetter);
    token += tokenLetter;
  }

  // 7. return your token variable (don't forget the semicolon!).
  return token;
}


